framework_css:
/*
 * Global design system for Universal Experts e-commerce
 * Based on provided UI: flat yellow/blue header, black utility bar, light search strip.
 */

:root {
    /* Color palette */
    --color-primary-yellow: #FFD600;
    --color-primary-blue: #0053A6;

    --color-black: #000000;
    --color-white: #FFFFFF;
    --color-bg-page: #F5F5F5;
    --color-border-subtle: #D9D9D9;

    --color-accent-success: #28A745;
    --color-accent-whatsapp: #25D366;
    --color-accent-error: #E53935;

    --color-text-main: #111111;
    --color-text-muted: #757575;
    --color-text-inverse: #FFFFFF;

    /* Typography */
    --font-heading: "Space Grotesk", Helvetica, sans-serif;
    --font-body: "Work Sans", Arial, sans-serif;

    --font-size-h1: 32px;
    --font-size-h2: 24px;
    --font-size-h3: 20px;
    --font-size-body: 15px;
    --font-size-small: 12px;

    --font-weight-light: 300;
    --font-weight-regular: 400;
    --font-weight-medium: 500;
    --font-weight-semibold: 600;
    --font-weight-bold: 700;

    /* Line heights */
    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.75;

    /* Spacing scale (8px base) */
    --space-xxs: 4px;
    --space-xs: 8px;
    --space-sm: 16px;
    --space-md: 24px;
    --space-lg: 32px;
    --space-xl: 48px;
    --space-xxl: 64px;

    /* Layout */
    --container-max-width: 1160px;

    /* Borders & radius */
    --radius-soft: 4px;
    --radius-pill: 999px;

    /* Shadows (very subtle, flat style) */
    --shadow-subtle: 0 2px 4px rgba(0, 0, 0, 0.06);
}

/* Global reset-ish styles */
* {
    box-sizing: border-box;
}

html,
body {
    margin: 0;
    padding: 0;
}

body {
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
    color: var(--color-text-main);
    background-color: var(--color-bg-page);
    -webkit-font-smoothing: antialiased;
}

img {
    max-width: 100%;
    display: block;
}

a {
    color: inherit;
}

.container {
    width: 100%;
    max-width: var(--container-max-width);
    margin-left: auto;
    margin-right: auto;
    padding-left: var(--space-md);
    padding-right: var(--space-md);
}

.site-main {
    min-height: 40vh;
    background-color: var(--color-white);
}

/* ----------------------
   Header
   ---------------------- */

.site-header {
    font-family: var(--font-body);
}

/* Top black utility bar */
.top-bar {
    background-color: var(--color-black);
    color: var(--color-text-inverse);
    font-size: var(--font-size-small);
}

.top-bar__inner {
    display: flex;
    align-items: center;
    padding-top: 6px;
    padding-bottom: 6px;
    white-space: nowrap;
    overflow: hidden;
}

.top-bar__brand {
    font-weight: var(--font-weight-semibold);
    letter-spacing: 0.05em;
    text-transform: uppercase;
}

.top-bar__dots {
    flex: 1;
    margin-left: var(--space-xs);
    margin-right: var(--space-xs);
    opacity: 0.75;
}

.top-bar__tagline {
    opacity: 0.9;
}

/* Main yellow header */
.main-header {
    background-color: var(--color-primary-yellow);
}

.main-header__inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding-top: var(--space-sm);
    padding-bottom: var(--space-sm);
    gap: var(--space-md);
}

/* Logo / brand */
.brand {
    display: inline-flex;
    align-items: center;
    text-decoration: none;
    color: var(--color-black);
    gap: var(--space-xs);
}

.brand-mark {
    position: relative;
    width: 40px;
    height: 40px;
    border-radius: var(--radius-soft);
    background-color: var(--color-primary-yellow);
    border: 2px solid var(--color-primary-blue);
    display: inline-block;
    overflow: hidden;
}

.brand-mark__circle {
    position: absolute;
    inset: 4px;
    border-radius: 50%;
    background-color: var(--color-primary-blue);
}

.brand-mark__bar {
    position: absolute;
    top: 4px;
    bottom: 4px;
    width: 30%;
    background-color: var(--color-white);
}

.brand-mark__bar--left {
    left: 9px;
}

.brand-mark__bar--right {
    right: 9px;
}

.brand-text {
    display: flex;
    flex-direction: column;
    font-family: var(--font-heading);
    line-height: 1.1;
}

.brand-text__line {
    font-size: 14px;
    font-weight: var(--font-weight-bold);
    letter-spacing: 0.08em;
}

/* Primary navigation */
.primary-nav {
    flex: 1;
}

.primary-nav__list {
    display: flex;
    align-items: center;
    justify-content: flex-end;
    gap: var(--space-md);
    list-style: none;
    margin: 0;
    padding: 0;
}

.primary-nav__link {
    position: relative;
    text-decoration: none;
    font-size: 14px;
    font-weight: var(--font-weight-medium);
    color: var(--color-black);
    padding: 4px 0;
}

.primary-nav__link::after {
    content: "";
    position: absolute;
    left: 0;
    bottom: -4px;
    width: 0;
    height: 2px;
    background-color: var(--color-primary-blue);
    transition: width 0.2s ease-out;
}

.primary-nav__link:hover::after,
.primary-nav__link:focus-visible::after {
    width: 100%;
}

.primary-nav__item--cart {
    margin-left: var(--space-lg);
}

.primary-nav__link--cart {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    padding: 4px 0;
}

.cart-icon {
    width: 18px;
    height: 18px;
    border-radius: 3px;
    border: 2px solid var(--color-black);
    position: relative;
}

.cart-icon::before,
.cart-icon::after {
    content: "";
    position: absolute;
    left: 50%;
    transform: translateX(-50%);
    background-color: var(--color-black);
}

.cart-icon::before {
    bottom: -4px;
    width: 10px;
    height: 2px;
}

.cart-icon::after {
    bottom: -7px;
    width: 4px;
    height: 4px;
    border-radius: 50%;
}

.cart-label {
    font-weight: var(--font-weight-medium);
}

.cart-count {
    min-width: 16px;
    height: 16px;
    border-radius: 50%;
    background-color: var(--color-accent-error);
    color: var(--color-text-inverse);
    font-size: 10px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
}

/* Search / browse strip (white bar) */
.search-strip {
    background-color: var(--color-white);
    border-bottom: 1px solid var(--color-border-subtle);
}

.search-strip__inner {
    display: grid;
    grid-template-columns: 280px minmax(0, 1fr) 220px;
    align-items: stretch;
    gap: 0;
}

.search-strip__browse,
.search-strip__input,
.search-strip__category {
    display: flex;
    align-items: center;
    background-color: var(--color-white);
    border-top: 1px solid var(--color-border-subtle);
    border-bottom: 1px solid var(--color-border-subtle);
}

.search-strip__browse {
    border-left: 1px solid var(--color-border-subtle);
    border-right: none;
    padding: 0 var(--space-md);
    gap: var(--space-xs);
}

.search-strip__input {
    background-color: #FAFAFA;
    border-left: none;
    border-right: none;
    padding: 0 var(--space-md);
}

.search-strip__category {
    border-right: 1px solid var(--color-border-subtle);
    border-left: none;
    padding: 0 var(--space-md);
    justify-content: space-between;
}

.search-strip__browse,
.search-strip__input,
.search-strip__category {
    height: 56px;
    font-size: 14px;
}

.browse-icon {
    width: 18px;
    height: 14px;
    border-top: 2px solid var(--color-black);
    border-bottom: 2px solid var(--color-black);
    position: relative;
}

.browse-icon::before {
    content: "";
    position: absolute;
    left: 0;
    right: 0;
    top: 50%;
    transform: translateY(-50%);
    border-top: 2px solid var(--color-black);
}

.browse-label {
    font-weight: var(--font-weight-medium);
}

.search-placeholder {
    color: var(--color-text-muted);
}

.category-label {
    color: #555555;
}

.category-arrow {
    width: 10px;
    height: 10px;
    border-left: 2px solid #555555;
    border-bottom: 2px solid #555555;
    transform: rotate(-45deg);
    margin-left: var(--space-xs);
}

/* ----------------------
   Footer
   ---------------------- */

.site-footer {
    background-color: var(--color-primary-blue);
    color: var(--color-text-inverse);
    padding-top: var(--space-xl);
    padding-bottom: var(--space-lg);
    margin-top: var(--space-xl);
}

.footer__inner {
    display: grid;
    grid-template-columns: minmax(0, 2fr) minmax(0, 3fr) minmax(0, 2fr);
    gap: var(--space-lg);
    align-items: flex-start;
}

.footer__brand {
    font-size: 14px;
}

.footer__logo {
    display: flex;
    align-items: center;
    gap: var(--space-xs);
    margin-bottom: var(--space-xs);
}

.footer-logo-mark {
    position: relative;
    width: 34px;
    height: 34px;
    border-radius: var(--radius-soft);
    background-color: var(--color-primary-yellow);
    border: 2px solid var(--color-primary-yellow);
    overflow: hidden;
}

.footer-logo-mark__circle {
    position: absolute;
    inset: 4px;
    border-radius: 50%;
    background-color: var(--color-primary-blue);
}

.footer-logo-mark__bar {
    position: absolute;
    top: 4px;
    bottom: 4px;
    width: 30%;
    background-color: var(--color-white);
}

.footer-logo-mark__bar--left {
    left: 8px;
}

.footer-logo-mark__bar--right {
    right: 8px;
}

.footer-logo-text {
    font-family: var(--font-heading);
    font-size: 12px;
    font-weight: var(--font-weight-semibold);
    letter-spacing: 0.08em;
}

.footer-logo-text__line {
    display: block;
}

.footer__tagline {
    margin: 0;
    margin-top: var(--space-xs);
    max-width: 260px;
    font-size: 13px;
    line-height: var(--line-height-relaxed);
    opacity: 0.9;
}

.footer-nav__list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: flex;
    flex-wrap: wrap;
    gap: var(--space-xs) var(--space-lg);
}

.footer-nav__link {
    text-decoration: none;
    font-size: 14px;
    color: rgba(255, 255, 255, 0.9);
}

.footer-nav__link:hover,
.footer-nav__link:focus-visible {
    text-decoration: underline;
}

.footer__meta {
    font-size: 12px;
    text-align: right;
    align-self: flex-end;
}

.footer__copyright {
    margin: 0;
    opacity: 0.9;
}

/* ----------------------
   Responsive adjustments
   ---------------------- */

@media (max-width: 1024px) {
    .primary-nav__list {
        gap: var(--space-sm);
        flex-wrap: wrap;
        justify-content: flex-end;
    }

    .primary-nav__item--cart {
        margin-left: var(--space-sm);
    }

    .search-strip__inner {
        grid-template-columns: 240px minmax(0, 1fr) 200px;
    }

    .footer__inner {
        grid-template-columns: minmax(0, 1.5fr) minmax(0, 2fr) minmax(0, 1.5fr);
    }
}

@media (max-width: 768px) {
    .top-bar__dots {
        display: none;
    }

    .main-header__inner {
        flex-direction: column;
        align-items: flex-start;
        gap: var(--space-sm);
    }

    .primary-nav__list {
        justify-content: flex-start;
        row-gap: 6px;
    }

    .search-strip__inner {
        grid-template-columns: 1fr;
    }

    .search-strip__browse,
    .search-strip__input,
    .search-strip__category {
        border-left: 1px solid var(--color-border-subtle);
        border-right: 1px solid var(--color-border-subtle);
    }

    .search-strip__input {
        border-top: none;
        border-bottom: none;
    }

    .footer__inner {
        grid-template-columns: 1fr;
        text-align: left;
    }

    .footer__meta {
        text-align: left;
    }
}

@media (max-width: 480px) {
    .brand-text__line {
        font-size: 12px;
    }

    .primary-nav__link {
        font-size: 13px;
    }

    .search-strip__browse,
    .search-strip__input,
    .search-strip__category {
        height: 48px;
    }
}
